     1|/**
     2| * CanonicalInvestmentReelCard — the ONE shared reel card for IVX.
     3| *
     4| * Used by:
     5| *   • Main/Home feed (mode="feed")
     6| *   • Reels module (mode="reel")
     7| *   • Landing page (mode="feed")
     8| *
     9| * Visual design (owner-approved):
    10| *   Full-bleed vertical media (video or image)
    11| *   Investment + Active badges (top-left)
    12| *   Property title + location (bottom-left, over gradient)
    13| *   ROI / Min Investment / Min Ownership metrics
    14| *   Tokenized / JV Deal / Buyer category options
    15| *   Right-side action rail: Like, Comment, Save, Share, Audio
    16| *   View Deal + Invest Now CTAs (bottom)
    17| *
    18| * Data sources:
    19| *   Accepts a unified `CanonicalReelData` props object that can be
    20| *   mapped from FeedVideo, HomeFeedDeal, PublishedDealCardModel, or
    21| *   ParsedJVDeal — all via the adapter functions in this file.
    22| */
    23|import React, { memo, useCallback, useEffect, useMemo, useRef, useState } from 'react';
    24|import {
    25|  View,
    26|  Text,
    27|  StyleSheet,
    28|  TouchableOpacity,
    29|  Share,
    30|  Alert,
    31|  AppState,
    32|  Platform,
    33|  useWindowDimensions,
    34|  type ViewStyle,
    35|} from 'react-native';
    36|import { ResizeMode } from 'expo-av';
    37|import { LinearGradient } from 'expo-linear-gradient';
    38|import { Image } from 'expo-image';
    39|import { useSafeAreaInsets } from 'react-native-safe-area-context';
    40|import * as Haptics from 'expo-haptics';
    41|import {
    42|  Heart,
    43|  MessageCircle,
    44|  Share2,
    45|  Bookmark,
    46|  Volume2,
    47|  VolumeX,
    48|  Play,
    49|  Hexagon,
    50|  Users,
    51|  Home,
    52|} from 'lucide-react-native';
    53|import Colors from '@/constants/colors';
    54|import SafeVideo from '@/components/SafeVideo';
    55|import ReelVideoPlayer from '@/components/ReelVideoPlayer';
    56|import { formatCount, compactCurrency } from '@/lib/reel-formatters';
    57|import { toggleProjectLike, trackProjectShare } from '@/lib/project-engagement';
    58|import { toggleVideoSave, getViewerId, buildVideoShareUrl } from '@/lib/video-platform';
    59|
    60|// ─── Types ─────────────────────────────────────────────────────────────
    61|
    62|export type ReelMode = 'reel' | 'feed';
    63|export type ReelMediaType = 'video' | 'image';
    64|
    65|export interface CanonicalReelData {
    66|  /** Unique identifier for this reel item (video ID or deal ID). */
    67|  reelId: string;
    68|  /** Linked JV deal ID (used for View Deal / Invest Now navigation). */
    69|  dealId: string | null;
    70|  /** Property ID if different from dealId. */
    71|  propertyId: string | null;
    72|  /** Investment ID if different from dealId. */
    73|  investmentId: string | null;
    74|  /** URL slug for deep linking. */
    75|  slug: string | null;
    76|  /** Display title (property name or video title). */
    77|  title: string;
    78|  /** Subtitle / tour label. */
    79|  subtitle: string;
    80|  /** Location string (city, state). */
    81|  location: string | null;
    82|  /** Primary media URL (video or image). */
    83|  mediaUrl: string | null;
    84|  /** Media type — video or image. */
    85|  mediaType: ReelMediaType;
    86|  /** HLS adaptive stream URL (preferred for video). */
    87|  hlsUrl: string | null;
    88|  /** Poster/thumbnail URL for video. */
    89|  posterUrl: string | null;
    90|  /** Blurred placeholder URL for instant first paint. */
    91|  previewBlurUrl: string | null;
    92|  /** Expected ROI percentage. */
    93|  roi: number | null;
    94|  /** Minimum investment amount in dollars. */
    95|  minimumInvestment: number | null;
    96|  /** Minimum ownership percentage. */
    97|  minimumOwnership: string | null;
    98|  /** Deal status (published, active, etc.). */
    99|  status: string;
   100|  /** Deal category (jv, development, etc.). */
   101|  category: string | null;
   102|  /** Like count. */
   103|  likeCount: number;
   104|  /** Comment count. */
   105|  commentCount: number;
   106|  /** Save count. */
   107|  saveCount: number;
   108|  /** Share count. */
   109|  shareCount: number;
   110|  /** Whether the current user has liked this reel. */
   111|  isLiked: boolean;
   112|  /** Whether the current user has saved this reel. */
   113|  isSaved: boolean;
   114|  /** Whether audio is enabled (video only). */
   115|  audioEnabled: boolean;
   116|  /** Creator ID for follow tracking. */
   117|  creatorId: string | null;
   118|  /** Full deal URL for deep-link navigation. */
   119|  dealUrl: string | null;
   120|}
   121|
   122|export interface CanonicalInvestmentReelCardProps {
   123|  data: CanonicalReelData;
   124|  mode: ReelMode;
   125|  /** Whether this card is the active/visible item (reel mode only). */
   126|  isActive: boolean;
   127|  /** Whether to mount the video player (reel mode — active ± 1 only). */
   128|  shouldMountVideo: boolean;
   129|  /** Whether audio is muted globally (reel mode). */
   130|  isMuted: boolean;
   131|  /** Card height for feed mode (default: 520). */
   132|  feedHeight: number;
   133|  /** Callbacks. */
   134|  onOpenDeal: (data: CanonicalReelData) => void;
   135|  onInvest: (data: CanonicalReelData) => void;
   136|  onLike: (data: CanonicalReelData) => void;
   137|  onComment: (data: CanonicalReelData) => void;
   138|  onSave: (data: CanonicalReelData) => void;
   139|  onShare: (data: CanonicalReelData) => void;
   140|  onToggleMute: () => void;
   141|  /** Test ID prefix. */
   142|  testIDPrefix?: string;
   143|}
   144|
   145|// ─── Investment options ────────────────────────────────────────────────
   146|
   147|interface InvestmentOption {
   148|  id: string;
   149|  label: string;
   150|  icon: React.ReactNode;
   151|  tint: string;
   152|}
   153|
   154|function useInvestmentOptions(dealType: string | null | undefined): InvestmentOption[] {
   155|  const t = (dealType ?? '').toLowerCase();
   156|  const tokenized: InvestmentOption = {
   157|    id: 'tokenized',
   158|    label: 'Tokenized',
   159|    icon: <Hexagon size={16} color={Colors.primary} />,
   160|    tint: Colors.primary,
   161|  };
   162|  const jvDeals: InvestmentOption = {
   163|    id: 'jvDeals',
   164|    label: 'JV Deal',
   165|    icon: <Users size={16} color={Colors.blue} />,
   166|    tint: Colors.blue,
   167|  };
   168|  const buyers: InvestmentOption = {
   169|    id: 'buyers',
   170|    label: 'Buyer',
   171|    icon: <Home size={16} color={Colors.green} />,
   172|    tint: Colors.green,
   173|  };
   174|  switch (t) {
   175|    case 'jv':
   176|    case 'equity_split':
   177|    case 'hybrid':
   178|      return [tokenized, jvDeals, buyers];
   179|    case 'development':
   180|    case 'new_construction':
   181|    case 'rehab_construction':
   182|      return [jvDeals, tokenized, buyers];
   183|    case 'profit_sharing':
   184|      return [tokenized, buyers, jvDeals];
   185|    default:
   186|      return [tokenized, jvDeals, buyers];
   187|  }
   188|}
   189|
   190|// ─── Component ─────────────────────────────────────────────────────────
   191|
   192|const CanonicalInvestmentReelCard = memo(function CanonicalInvestmentReelCard({
   193|  data,
   194|  mode,
   195|  isActive,
   196|  shouldMountVideo,
   197|  isMuted,
   198|  feedHeight = 520,
   199|  onOpenDeal,
   200|  onInvest,
   201|  onLike,
   202|  onComment,
   203|  onSave,
   204|  onShare,
   205|  onToggleMute,
   206|  testIDPrefix = 'reel-card',
   207|}: CanonicalInvestmentReelCardProps) {
   208|  const insets = useSafeAreaInsets();
   209|  const { height: screenHeight } = useWindowDimensions();
   210|  const [paused, setPaused] = useState<boolean>(false);
   211|  const [showHeart, setShowHeart] = useState<boolean>(false);
   212|  const [progress, setProgress] = useState<number>(0);
   213|  const [liked, setLiked] = useState<boolean>(data.isLiked);
   214|  const [likeCount, setLikeCount] = useState<number>(data.likeCount);
   215|  const [saved, setSaved] = useState<boolean>(data.isSaved);
   216|  const [saveCount, setSaveCount] = useState<number>(data.saveCount);
   217|  const [viewerId, setViewerId] = useState<string | null>(null);
   218|  const [appState, setAppState] = useState<string>('active');
   219|  const [isInViewport, setIsInViewport] = useState<boolean>(false);
   220|  const lastTapRef = useRef<number>(0);
   221|  const viewRef = useRef<View>(null);
   222|
   223|  const isReel = mode === 'reel';
   224|  const usableReelHeight = isReel
   225|    ? Math.max(0, screenHeight - insets.top - insets.bottom - (Platform.OS === 'android' ? 48 : 0))
   226|    : feedHeight;
   227|  const cardHeight = isReel ? usableReelHeight : feedHeight;
   228|
   229|  // Fetch viewer ID for engagement tracking
   230|  useEffect(() => {
   231|    let cancelled = false;
   232|    void getViewerId().then((id) => {
   233|      if (!cancelled) setViewerId(id);
   234|    });
   235|    return () => { cancelled = true; };
   236|  }, []);
   237|
   238|  // Pause video when app goes to background
